def _cast_value(value, col_type):
    """Cast a string value to the appropriate Python type based on column type."""
    if col_type == "integer":
        try:
            return int(value)
        except (ValueError, TypeError):
            raise ValueError(f"Expected integer value, got: '{value}'")
    elif col_type == "numeric":
        try:
            return float(value)
        except (ValueError, TypeError):
            raise ValueError(f"Expected numeric value, got: '{value}'")
    else:
        return str(value)


def execute_query(query, params):
    """Execute a query using the connection pool and return results."""
    conn = db_pool.getconn()
    try:
        with conn.cursor(cursor_factory=RealDictCursor) as cur:
            cur.execute(query, params)
            results = cur.fetchall()
        conn.commit()
        return results
    except Exception:
        conn.rollback()
        raise
    finally:
        db_pool.putconn(conn)


# GraphQL Types

class SearchFilterInput(graphene.InputObjectType):
    field = graphene.String(required=True, description="Column name to filter on")
    value = graphene.String(description="Value to filter by")
    operator = graphene.String(
        default_value="eq",
        description="Operator: eq, neq, like, starts_with, gt, gte, lt, lte, in, is_null, is_not_null"
    )


class SearchResultRecord(graphene.ObjectType):
    """A generic key-value record from search results."""
    data = graphene.JSONString(description="Record data as JSON")


class PaginationInfo(graphene.ObjectType):
    total_count = graphene.Int()
    limit = graphene.Int()
    offset = graphene.Int()
    has_next_page = graphene.Boolean()
    has_previous_page = graphene.Boolean()


class SearchResult(graphene.ObjectType):
    records = graphene.List(SearchResultRecord)
    pagination = graphene.Field(PaginationInfo)


class TableInfo(graphene.ObjectType):
    table_name = graphene.String()
    columns = graphene.List(graphene.String)
    text_searchable = graphene.List(graphene.String)
    sortable = graphene.List(graphene.String)


class Query(graphene.ObjectType):
    search = graphene.Field(
        SearchResult,
        table=graphene.String(required=True, description="Table to search"),
        filters=graphene.List(SearchFilterInput, description="Field-specific filters"),
        search_term=graphene.String(description="Full-text search term across text fields"),
        search_fields=graphene.List(
            graphene.String,
            description="Specific text fields to search (defaults to all text-searchable)"
        ),
        sort_by=graphene.String(description="Column to sort by"),
        sort_direction=graphene.String(
            default_value="ASC",
            description="Sort direction: ASC or DESC"
        ),
        limit=graphene.Int(default_value=20, description=f"Results per page (max {MAX_LIMIT})"),
        offset=graphene.Int(default_value=0, description="Offset for pagination"),
        return_columns=graphene.List(
            graphene.String,
            description="Specific columns to return (defaults to all)"
        ),
    )

    available_tables = graphene.List(
        TableInfo,
        description="List available tables and their searchable schema"
    )

    def resolve_search(self, info, table, filters=None, search_term=None,
                       search_fields=None, sort_by=None, sort_direction="ASC",
                       limit=20, offset=0, return_columns=None):
        try:
            # Convert filter inputs to dicts
            filter_dicts = None
            if filters:
                filter_dicts = [
                    {
                        "field": f.field,
                        "value": f.value,
                        "operator": f.operator or "eq",
                    }
                    for f in filters
                ]

            # Build and execute search query
            query, params = build_search_query(
                table_name=table,
                filters=filter_dicts,
                search_term=search_term,
                search_fields=search_fields,
                sort_by=sort_by,
                sort_direction=sort_direction,
                limit=limit,
                offset=offset,
                return_columns=return_columns,
            )

            results = execute_query(query, params)

            # Build and execute count query
            count_query, count_params = build_count_query(
                table_name=table,
                filters=filter_dicts,
                search_term=search_term,
                search_fields=search_fields,
            )

            count_results = execute_query(count_query, count_params)
            total_count = count_results[0]["total"] if count_results else 0

            validated_limit = validate_limit(limit)
            validated_offset = validate_offset(offset)

            records = [SearchResultRecord(data=dict(row)) for row in results]

            pagination = PaginationInfo(
                total_count=total_count,
                limit=validated_limit,
                offset=validated_offset,
                has_next_page=(validated_offset + validated_limit) < total_count,
                has_previous_page=validated_offset > 0,
            )

            return SearchResult(records=records, pagination=pagination)

        except ValueError as e:
            raise Exception(str(e))
        except Exception as e:
            # Log the actual error server-side, return generic message to client
            import logging
            logging.exception("Search query failed")
            raise Exception("An error occurred while processing your search request.")

    def resolve_available_tables(self, info):
        return [
            TableInfo(
                table_name=name,
                columns=list(schema["columns"].keys()),
                text_searchable=schema["text_searchable"],
                sortable=schema["sortable"],
            )
            for name, schema in ALLOWED_SEARCH_SCHEMA.items()
        ]


schema = graphene.Schema(query=Query)


def create_app():
    app = Flask(__name__)

    app.add_url_rule(
        "/graphql",
        view_func=GraphQLView.as_view(
            "graphql",
            schema=schema,
            graphiql=True,
        ),
    )

    return app


# Database initialization script
INIT_SQL = """
CREATE TABLE IF NOT EXISTS products (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT,
    category TEXT,
    price NUMERIC(10, 2),
    sku TEXT,
    brand TEXT
);

CREATE TABLE IF NOT EXISTS users (
    id SERIAL PRIMARY KEY,
    username TEXT NOT NULL UNIQUE,
    email TEXT NOT NULL,
    full_name TEXT,
    city TEXT,
    country TEXT
);

CREATE TABLE IF NOT EXISTS orders (
    id SERIAL PRIMARY KEY,
    order_number TEXT NOT NULL UNIQUE,
    status TEXT NOT NULL DEFAULT 'pending',
    total_amount NUMERIC(10, 2),
    customer_name TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Indexes for search performance
CREATE INDEX IF NOT EXISTS idx_products_name ON products USING gin (name gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_products_category ON products (category);
CREATE INDEX IF NOT EXISTS idx_products_brand ON products (brand);
CREATE INDEX IF NOT EXISTS idx_products_price ON products (price);

CREATE INDEX IF NOT EXISTS idx_users_username ON users USING gin (username gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_users_email ON users USING gin (email gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_users_full_name ON users USING gin (full_name gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_orders_order_number ON orders (order_number);
CREATE INDEX IF NOT EXISTS idx_orders_status ON orders (status);
CREATE INDEX IF NOT EXISTS idx_orders_customer_name ON orders USING gin (customer_name gin_trgm_ops);
"""


def init_db():
    """Initialize database tables and indexes."""
    conn = db_pool.getconn()
    try:
        with conn.cursor() as cur:
            # Enable trigram extension for ILIKE performance
            cur.execute("CREATE EXTENSION IF NOT EXISTS pg_trgm;")
            cur.execute(INIT_SQL)
        conn.commit()
        print("Database initialized successfully.")
    except Exception as e:
        conn.rollback()
        print(f"Database initialization failed: {e}")
        raise
    finally:
        db_pool.putconn(conn)


if __name__ == "__main__":
    try:
        init_db()
    except Exception:
        print("Warning: Could not initialize database. Make sure PostgreSQL is running.")

    app = create_app()
    app.run(host="127.0.0.1", port=5000, debug=False)